const trending = $('Fetch Trending').first().json;
const fearGreed = $('Fetch Fear & Greed').first().json;
const mlHealth = $('ML Health Check').first().json;

const topTokens = (trending.tokens || trending.trending || []).slice(0, 10);

return [{
  json: {
    trending: topTokens,
    fearGreed,
    mlHealth,
    features: topTokens.map(t => ({
      rsi: 50, macdHistogram: 0, bollingerPercentB: 0.5,
      fundingRate: 0, fearGreed: fearGreed.value || fearGreed.index || 50,
      rsiSlope: 0, volumeRatio: 1, emaCrossoverPct: 0, atrPct: 2,
      symbol: t.symbol || t.pair || t.name,
      timestamp: Date.now()
    }))
  }
}];

const data = $('Merge Data').first().json;
const mlResult = $input.first().json;
const predictions = mlResult.predictions || [];

const date = new Date().toISOString().split('T')[0];
const fg = data.fearGreed;
const fgVal = fg.value || fg.index || 0;
const fgLabel = fgVal >= 75 ? 'Extreme Greed' : fgVal >= 55 ? 'Greed' : fgVal >= 45 ? 'Neutral' : fgVal >= 25 ? 'Fear' : 'Extreme Fear';

let report = `VIZZOR DAILY REPORT — ${date}\n`;
report += `${'='.repeat(40)}\n\n`;

report += `MARKET SENTIMENT\n`;
report += `Fear & Greed Index: ${fgVal}/100 (${fgLabel})\n\n`;

report += `ML SIDECAR\n`;
report += `Models: ${(data.mlHealth.models || []).map(m => m.name).join(', ')}\n`;
report += `Predictions served: ${data.mlHealth.predictionsServed || 0}\n\n`;

report += `TOP TRENDING TOKENS (with ML predictions)\n`;
for (let i = 0; i < data.trending.length; i++) {
  const t = data.trending[i];
  const sym = t.symbol || t.pair || t.name;
  const price = t.priceUsd || t.price || 0;
  const change = t.priceChange24h || t.change24h || 0;
  const pred = predictions[i];
  const dir = pred ? pred.direction : '?';
  const conf = pred ? Math.round((pred.probability || pred.confidence || 0) * 100) : 0;
  report += `${i + 1}. ${sym} — $${Number(price).toLocaleString()} (${change > 0 ? '+' : ''}${Number(change).toFixed(1)}%) | ML: ${dir} ${conf}%\n`;
}

report += `\n— Generated by Vizzor v0.9.0`;

return [{ json: { report } }];
